/* ── Cercle de progression ───────────────────────── */
function CircularProgress({ value, size = 72, stroke = 4 }) {
  const r = (size - stroke) / 2;
  const circ = 2 * Math.PI * r;
  const offset = circ - (value / 100) * circ;
  return (
    <div style={{ position:"relative", width:size, height:size, display:"flex", alignItems:"center", justifyContent:"center" }}>
      <svg width={size} height={size} style={{ transform:"rotate(-90deg)", position:"absolute" }}>
        {/* Piste */}
        <circle cx={size/2} cy={size/2} r={r}
          fill="none" stroke="rgba(255,255,255,0.15)" strokeWidth={stroke}/>
        {/* Arc blanc */}
        <circle cx={size/2} cy={size/2} r={r}
          fill="none" stroke="white" strokeWidth={stroke}
          strokeLinecap="round"
          strokeDasharray={circ}
          strokeDashoffset={offset}
          style={{ transition:"stroke-dashoffset 0.1s linear" }}/>
      </svg>
      {/* Pourcentage au centre */}
      <span style={{ fontSize:13, fontWeight:700, color:"white", fontFamily:"Century Gothic, Trebuchet MS, sans-serif" }}>
        {value}%
      </span>
    </div>
  );
}

/* ── SPLASH ─────────────────────────────────────── */
function SplashScreen({ onDone }) {
  const [phase, setPhase] = useState("in");
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    // Phase : in → hold après 300ms
    const t1 = setTimeout(() => setPhase("hold"), 300);
    // Barre de chargement : monte de 0 à 100 sur 4 secondes
    const start = Date.now();
    const duration = 4000;
    const tick = setInterval(() => {
      const elapsed = Date.now() - start;
      const pct = Math.min(100, Math.round((elapsed / duration) * 100));
      setProgress(pct);
      if (pct >= 100) clearInterval(tick);
    }, 30);
    // Sortie à 4.3s
    const t2 = setTimeout(() => setPhase("out"), 4300);
    const t3 = setTimeout(() => onDone(), 5000);
    return () => {
      clearTimeout(t1); clearTimeout(t2); clearTimeout(t3);
      clearInterval(tick);
    };
  }, []);

  return (
    <div style={{
      position:"fixed",
      top:0, left:0, right:0, bottom:0,
      width:"100%",
      height:"100%",
      zIndex:100,
      background:`linear-gradient(160deg,${C.primaryDark} 0%,${C.primary} 60%,#2050C0 100%)`,
      display:"flex", flexDirection:"column",
      alignItems:"center", justifyContent:"space-between",
      transition:"opacity 0.8s ease",
      opacity:phase==="out"?0:1,
      overflow:"hidden",
      touchAction:"none",
      userSelect:"none",
      WebkitOverflowScrolling:"touch",
    }}>

      {/* Cercles décoratifs */}
      <div style={{position:"absolute",width:360,height:360,borderRadius:"50%",border:"2px solid rgba(230,48,48,0.18)",top:-90,right:-90,transition:"all 1.4s ease",transform:phase==="hold"?"scale(1)":"scale(0.3)",pointerEvents:"none"}}/>
      <div style={{position:"absolute",width:240,height:240,borderRadius:"50%",border:"1px solid rgba(255,255,255,0.06)",bottom:-60,left:-60,transition:"all 1.6s ease",transform:phase==="hold"?"scale(1)":"scale(0.3)",pointerEvents:"none"}}/>

      {/* Espace haut — flexible */}
      <div style={{flex:1}}/>

      {/* Logo + slogan — centré verticalement */}
      <div style={{
        display:"flex", flexDirection:"column", alignItems:"center",
        transition:"opacity 1s ease, transform 1s ease",
        opacity:phase==="in"?0:1,
        transform:phase==="in"?"translateY(40px) scale(0.75)":"translateY(0) scale(1)",
      }}>
        {/* Logo carré */}
        <div style={{
          transition:"transform 1.1s cubic-bezier(0.34,1.56,0.64,1)",
          transform:phase==="in"?"scale(0.2) rotate(-15deg)":"scale(1) rotate(0deg)",
          marginBottom:28,
        }}>
          <MaraeLogo size={160}/>
        </div>

        {/* MARAE CENTER en dégradé + slogan */}
        <div style={{
          display:"flex", flexDirection:"column", alignItems:"center", gap:6,
          transition:"opacity 1.2s ease 0.5s",
          opacity:phase==="hold"?1:0,
        }}>
          {/* Texte MARAE CENTER avec dégradé bleu-blanc-rouge via SVG */}
          <svg viewBox="0 0 320 44" width="310" height="44" xmlns="http://www.w3.org/2000/svg">
            <text
              x="160" y="34"
              textAnchor="middle"
              fontFamily="'Century Gothic', 'Trebuchet MS', sans-serif"
              fontWeight="900"
              fontSize="32"
              letterSpacing="5"
              fill="#FFFFFF"
              style={{filter:"drop-shadow(0px 2px 6px rgba(0,0,0,0.4))"}}
            >
              MARAE CENTER
            </text>
          </svg>
          {/* Slogan */}
          <div style={{
            fontSize:11, color:"rgba(255,255,255,0.6)",
            fontStyle:"italic", letterSpacing:2,
            fontFamily:"Century Gothic, Trebuchet MS, sans-serif",
          }}>
            VOTRE APPLICATION MUTUALISTE
          </div>
        </div>
      </div>

      {/* Espace bas — flexible */}
      <div style={{flex:1}}/>

      {/* Cercle de chargement — ancré en bas */}
      <div style={{
        paddingBottom:40,
        display:"flex", flexDirection:"column", alignItems:"center", gap:8,
        transition:"opacity 1s ease 0.4s",
        opacity:phase==="hold"?1:0,
      }}>
        <CircularProgress value={progress} size={68} stroke={4}/>
        <div style={{fontSize:9, color:"rgba(255,255,255,0.2)", letterSpacing:2}}>
          VERSION 1.0.0
        </div>
      </div>

      <style>{`
        @keyframes spin{to{transform:rotate(360deg);}}
        html, body, #root {
          height: 100% !important;
          max-height: 100% !important;
          overflow: hidden !important;
          position: fixed !important;
          width: 100% !important;
          top: 0 !important;
          left: 0 !important;
        }
      `}</style>
    </div>
  );
}

